export const crmMeetings = pgTable(
	'crm_meetings',
	{
		id: uuid('id').primaryKey().defaultRandom(),
		leadId: uuid('lead_id').notNull().references(() => crmLeads.id, { onDelete: 'cascade' }),
		organizerId: uuid('organizer_id').references(() => crmUsers.id, { onDelete: 'set null' }),
		leadOrganizerId: uuid('lead_organizer_id').references(() => crmOrganizers.id, { onDelete: 'set null' }),
		startAt: timestamp('start_at', { withTimezone: true }).notNull(),
		meetingUrl: text('meeting_url'),
		notes: text('notes'),
		outcome: text('outcome'),
		deletedAt: timestamp('deleted_at', { withTimezone: true }),
		// ... reminder checkpoint columns
	},
	(t) => [index('crm_meetings_lead_idx').on(t.leadId)]
);
